SELECT id, accessType, create_time, user_id, name, user_type_names, project_group_names, area_name, floor_name, room_id, room_name,
       is_shared_card, is_keep_card, is_borrowed_card,
       feed_source, feed_summary_zh, feed_detail_zh, device_display_name
FROM aro_access_log
WHERE name LIKE #{pattern}
   OR user_id LIKE #{pattern}
   OR project_group_names LIKE #{pattern}
ORDER BY create_time DESC
LIMIT #{limit}


