SELECT project_name AS projectName, SUM(male_qty + female_qty) AS totalQuantity FROM aro_animal_order WHERE DATE_FORMAT(create_time, '%Y-%m') = DATE_FORMAT(NOW(), '%Y-%m') AND area_name LIKE '%浦东%' AND area_name LIKE '%浦西%'
AND pi_name NOT IN
#{item}
AND project_name NOT IN
#{item}
GROUP BY project_name ORDER BY totalQuantity DESC LIMIT 10


SELECT project_name AS projectName, pi_name AS piName
FROM aro_animal_order


        project_name LIKE #{pattern}
        OR pi_name LIKE #{pattern}


GROUP BY project_name, pi_name
ORDER BY SUM(male_qty + female_qty) DESC
LIMIT 1 OFFSET #{offset}

SELECT *
FROM aro_animal_order
WHERE project_name = #{projectName}
  AND pi_name = #{piName}
ORDER BY arrival_date DESC


SELECT COUNT(DISTINCT CONCAT(project_name, pi_name))
FROM aro_animal_order


        project_name LIKE #{pattern}
        OR pi_name LIKE #{pattern}

SELECT rs.room_id AS roomId, CASE WHEN rs.room_id LIKE 'SUITE_%' THEN REPLACE(REPLACE(rs.room_id, 'SUITE_', ''), '_', ' ') ELSE COALESCE( ( SELECT CONCAT(COALESCE(area_name, ''), IF(area_name IS NULL OR area_name = '', '', ' '), room_name) FROM aro_access_log WHERE room_id = rs.room_id AND room_name IS NOT NULL LIMIT 1 ), rs.room_id ) END AS roomName, MAX(rs.max_capacity) AS maxCapacity, SUM(COALESCE(stat.currentPeople, 0)) AS currentPeople, SUM(COALESCE(stat.borrowedCards, 0)) AS borrowedCards FROM aro_room_settings rs LEFT JOIN ( SELECT a.room_id, a.room_name, a.area_name, SUM(CASE WHEN a.accessType = 1 THEN 1 ELSE 0 END) AS currentPeople, SUM(CASE WHEN a.accessType = 1 AND COALESCE(a.is_shared_card, 0) = 0 THEN 1 WHEN a.accessType IN (2, 3) AND COALESCE(a.is_keep_card, 0) = 1 THEN 1 ELSE 0 END) AS borrowedCards FROM aro_access_log a INNER JOIN ( SELECT room_id, user_id, MAX(create_time) AS max_time FROM aro_access_log WHERE create_time >= CONCAT(CURDATE(), ' 00:00:00') GROUP BY room_id, user_id ) latest ON a.room_id = latest.room_id AND a.user_id = latest.user_id AND a.create_time = latest.max_time GROUP BY a.room_id, a.room_name, a.area_name ) stat ON ( rs.room_id = stat.room_id OR rs.room_id = stat.room_name OR ( rs.room_id LIKE 'SUITE_%' AND rs.room_id LIKE CONCAT('SUITE_', stat.area_name, '_%') AND stat.room_name LIKE CONCAT('%', REPLACE(rs.room_id, CONCAT('SUITE_', stat.area_name, '_'), ''), '%') ) )
rs.room_id = #{roomId}
GROUP BY rs.room_id

