mapper.select:
SELECT log.id, log.user_id, log.accessType, log.create_time, log.name, log.user_type_names, log.project_group_names, log.area_name, log.room_name, log.feed_source, log.feed_summary_zh, log.feed_detail_zh, log.is_shared_card, log.is_keep_card, log.is_borrowed_card, CASE WHEN m.aro_user_id IS NULL THEN 0 ELSE 1 END AS has_physical_card_mapping, CASE WHEN m.aro_user_id IS NOT NULL AND COALESCE(log.is_borrowed_card, 0) = 0 THEN 1 ELSE 0 END AS is_own_card, COALESCE(m.freeze_exempt_flag, 0) AS freeze_exempt_flag FROM aro_access_log log LEFT JOIN twin_card_mapping m ON m.aro_user_id = log.user_id WHERE 1 = 1
AND ( log.name LIKE #{keywordPattern} OR log.user_id LIKE #{keywordPattern} OR log.project_group_names LIKE #{keywordPattern} )
AND log.create_time >= #{startTime} AND log.create_time <= #{endTime} AND log.accessType = #{actionType}
AND log.area_name LIKE #{campusPattern}
AND log.room_name LIKE CONCAT(#{floor}, '%')
AND log.room_name LIKE #{roomPattern}
AND log.user_id NOT IN (SELECT user_id FROM twin_blacklist)
ORDER BY log.create_time DESC LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*)
FROM aro_access_log
WHERE user_id = #{userId}
  AND area_name LIKE '%浦西%'
  AND create_time LIKE #{todayPrefix}

SELECT
    COALESCE(SUM(CASE WHEN area_name LIKE '%浦东%' THEN 1 ELSE 0 END), 0) AS pudongCnt,
    COALESCE(SUM(CASE WHEN area_name LIKE '%浦西%' THEN 1 ELSE 0 END), 0) AS puxiCnt
FROM aro_access_log
WHERE user_id = #{userId}
  AND create_time LIKE #{todayPrefix}

